import requests
import json

# --- Configuration ---
RABBITMQ_HOST = 'localhost'
RABBITMQ_API_PORT = 15672
RABBITMQ_USER = 'your_admin_user'
RABBITMQ_PASSWORD = 'your_admin_password'

# Base URL for the RabbitMQ Management API
BASE_URL = f"http://{RABBITMQ_HOST}:{RABBITMQ_API_PORT}/api"

# Headers for API requests
HEADERS = {'Content-Type': 'application/json'}
AUTH = (RABBITMQ_USER, RABBITMQ_PASSWORD)

# --- Virtual Hosts and Users/Permissions Configuration ---
VHOST_CONFIG = {
    'app_accounting': {
        'user': 'accounting_user',
        'password': 'accounting_password_secure',
        'permissions': {
            'configure': '.*',  # All configure permissions
            'write': '.*',      # All write permissions
            'read': '.*'        # All read permissions
        }
    },
    'app_shipping': {
        'user': 'shipping_user',
        'password': 'shipping_password_secure',
        'permissions': {
            'configure': '.*',
            'write': '.*',
            'read': '.*'
        }
    },
    'app_notifications': {
        'user': 'notifications_user',
        'password': 'notifications_password_secure',
        'permissions': {
            'configure': '.*',
            'write': '.*',
            'read': '.*'
        }
    }
}

# --- Helper Functions ---

def api_request(method, endpoint, data=None):
    """
    Makes an authenticated HTTP request to the RabbitMQ Management API.
    """
    url = f"{BASE_URL}{endpoint}"
    try:
        if data:
            response = requests.request(method, url, headers=HEADERS, auth=AUTH, data=json.dumps(data))
        else:
            response = requests.request(method, url, headers=HEADERS, auth=AUTH)

        response.raise_for_status() # Raise an HTTPError for bad responses (4xx or 5xx)
        print(f"[{method.upper()}] {endpoint}: Success")
        return response.json() if response.content else None
    except requests.exceptions.HTTPError as e:
        print(f"[{method.upper()}] {endpoint}: Error - {e}")
        print(f"Response content: {e.response.text}")
    except requests.exceptions.ConnectionError as e:
        print(f"Connection Error: Could not connect to RabbitMQ API at {BASE_URL}. Ensure RabbitMQ is running and API is enabled. Error: {e}")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    return None

def create_vhost(vhost_name):
    """
    Creates a new virtual host.
    """
    print(f"\n--- Creating VHost: {vhost_name} ---")
    endpoint = f"/vhosts/{vhost_name}"
    api_request('PUT', endpoint)

def create_user(username, password):
    """
    Creates a new user.
    """
    print(f"\n--- Creating User: {username} ---")
    endpoint = f"/users/{username}"
    data = {'password': password, 'tags': 'management'} # Add management tag to allow access to UI
    api_request('PUT', endpoint, data=data)

def set_permissions(vhost_name, username, configure, write, read):
    """
    Sets permissions for a user on a virtual host.
    """
    print(f"\n--- Setting Permissions for user '{username}' on vhost '{vhost_name}' ---")
    endpoint = f"/permissions/{vhost_name}/{username}"
    data = {
        'configure': configure,
        'write': write,
        'read': read
    }
    api_request('PUT', endpoint, data=data)

def get_vhosts():
    """
    Retrieves a list of all existing virtual hosts.
    """
    endpoint = "/vhosts"
    return api_request('GET', endpoint)

def get_users():
    """
    Retrieves a list of all existing users.
    """
    endpoint = "/users"
    return api_request('GET', endpoint)

# --- Main Script Logic ---

def configure_rabbitmq():
    print(f"Starting RabbitMQ Configuration for {len(VHOST_CONFIG)} applications.")

    existing_vhosts = get_vhosts()
    existing_vhost_names = {vhost['name'] for vhost in existing_vhosts} if existing_vhosts else set()
    print(f"Existing VHosts: {existing_vhost_names}")

    existing_users = get_users()
    existing_user_names = {user['name'] for user in existing_users} if existing_users else set()
    print(f"Existing Users: {existing_user_names}")

    for vhost_name, config in VHOST_CONFIG.items():
        user = config['user']
        password = config['password']
        permissions = config['permissions']

        # 1. Create Virtual Host
        if vhost_name not in existing_vhost_names:
            create_vhost(vhost_name)
        else:
            print(f"VHost '{vhost_name}' already exists. Skipping creation.")

        # 2. Create User
        if user not in existing_user_names:
            create_user(user, password)
        else:
            print(f"User '{user}' already exists. Skipping creation.")

        # 3. Set Permissions
        set_permissions(vhost_name, user, permissions['configure'], permissions['write'], permissions['read'])

    print("\nRabbitMQ Configuration Complete.")
    print("Please verify the setup in the RabbitMQ Management UI.")
    print(f"Management UI: http://{RABBITMQ_HOST}:{RABBITMQ_API_PORT}")

if __name__ == "__main__":
    configure_rabbitmq()